            </div>
          ))}
        </div>
      </section>

      {/* ▓▓ TREATMENTS ▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓ */}
      <section style={{ padding: '7rem 8vw', background: C.charcoal, position: 'relative', overflow: 'hidden' }}>
        {/* decorative lines */}
        <div style={{ position: 'absolute', top: 0, left: '8vw', width: '1px', height: '100%', background: 'rgba(255,255,255,.04)', pointerEvents: 'none' }} />
        <div style={{ position: 'absolute', top: 0, right: '8vw', width: '1px', height: '100%', background: 'rgba(255,255,255,.04)', pointerEvents: 'none' }} />

        <SectionHeader eyebrow="Nos soins" title="Traitements d'exception" subtitle="Du soin préventif à la transformation esthétique, des protocoles rigoureux adaptés à chaque patient." light />

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: '1.5rem' }}>
          {treatments.map(({ Icon, title, desc, tag: t }, i) => (
            <div key={title}
              onMouseEnter={() => setHTreat(i)} onMouseLeave={() => setHTreat(null)}
              style={{
                background: hTreat === i ? 'rgba(184,154,106,.08)' : 'rgba(255,255,255,.03)',
                border: `1px solid ${hTreat === i ? 'rgba(184,154,106,.35)' : 'rgba(255,255,255,.08)'}`,
                borderRadius: '18px', padding: '2.2rem 2rem',
                transform: hTreat === i ? 'translateY(-4px)' : 'none',
                transition: 'all .28s ease', cursor: 'default',
                animation: `scaleIn .6s ${0.05 * i}s ease both`, opacity: 0,
              }}>
              {tag(t)}
              <div style={{ marginBottom: '1rem', color: C.gold }}>
                <Icon c={C.gold} />
              </div>
              <h3 style={{ fontFamily: C.fd, fontWeight: 300, fontSize: '1.25rem', color: C.ivory, marginBottom: '.6rem' }}>{title}</h3>
              <p style={{ fontSize: '.87rem', fontWeight: 300, color: C.mutedLt, lineHeight: 1.75, margin: 0 }}>{desc}</p>
            </div>
          ))}
        </div>

        <div style={{ textAlign: 'center', marginTop: '3.5rem' }}>
          <button
            onMouseEnter={() => setHBtn('all')} onMouseLeave={() => setHBtn(null)}
            onClick={() => navigate('/services')}
            style={{
              display: 'inline-flex', alignItems: 'center', gap: '8px',
              fontFamily: C.fb, fontSize: '.85rem', fontWeight: 500, letterSpacing: '.05em',
              textTransform: 'uppercase', background: 'transparent',
              color: hBtn === 'all' ? C.gold : C.ivory,
              border: `1px solid ${hBtn === 'all' ? C.gold : 'rgba(255,255,255,.3)'}`,
              borderRadius: '100px', padding: '.85rem 2.2rem', cursor: 'pointer',
              transition: 'all .22s ease',
            }}>
            Voir tous les traitements <Ico.Arrow />
          </button>
        </div>
      </section>

      {/* ▓▓ REVIEWS ▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓ */}
      <section style={{ padding: '7rem 8vw', background: C.white }}>
        <SectionHeader eyebrow="Témoignages" title="Ce que disent nos patients" subtitle="Plus de 15 000 patients nous font confiance. Leurs mots reflètent notre engagement quotidien." />

        {/* Carousel */}
        <div style={{ position: 'relative' }}>
          {/* Cards */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: '1.4rem', alignItems: 'start' }}>
            {reviews.slice(review, review + 3).map(({ name, role, text, stars, initials }, i) => (
              <div key={name} style={{
                background: i === 1 ? C.charcoal : C.ivory,
                border: `1px solid ${i === 1 ? 'transparent' : C.ivoryMid}`,
                borderRadius: '20px', padding: '2.2rem',
                transform: i === 1 ? 'scale(1.03)' : 'scale(1)',
                boxShadow: i === 1 ? '0 30px 70px rgba(37,36,34,.18)' : 'none',
                animation: `fadeUp .6s ${i * 0.12}s ease both`, opacity: 0,
                transition: 'transform .3s ease',
              }}>
                <div style={{ marginBottom: '1.4rem', color: C.goldLt }}><Ico.Quote /></div>
                <p style={{
                  fontSize: '.93rem', fontWeight: 300,
                  color: i === 1 ? C.mutedLt : C.ink,
                  lineHeight: 1.8, marginBottom: '1.8rem', fontFamily: C.fd, fontStyle: 'italic',
                }}>"{text}"</p>
                <div style={{ display: 'flex', alignItems: 'center', gap: '.9rem' }}>
                  <div style={{
                    width: '44px', height: '44px', borderRadius: '50%',
                    background: i === 1 ? 'rgba(184,154,106,.2)' : C.goldPale,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: '.82rem', fontWeight: 500, color: C.gold, flexShrink: 0,
                  }}>{initials}</div>
                  <div>
                    <p style={{ fontSize: '.87rem', fontWeight: 500, color: i === 1 ? C.ivory : C.charcoal, margin: 0 }}>{name}</p>
                    <p style={{ fontSize: '.75rem', color: C.muted, margin: '.15rem 0 .4rem' }}>{role}</p>
                    <div style={{ display: 'flex', gap: '2px' }}>
                      {Array(stars).fill(0).map((_, j) => <Ico.StarFill key={j} />)}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Dots nav */}
          <div style={{ display: 'flex', justifyContent: 'center', gap: '8px', marginTop: '2.5rem' }}>
            {[0, 1, 2].map(d => (
              <button key={d}
                onClick={() => setReview(d)}
                style={{
                  width: d === review ? '28px' : '8px', height: '8px',
                  borderRadius: '100px', border: 'none', cursor: 'pointer',
                  background: d === review ? C.gold : C.ivoryDk,
                  transition: 'all .3s ease', padding: 0,
                }} />
            ))}
          </div>
        </div>
      </section>

      {/* ▓▓ FAQ ▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓ */}
      <section style={{ padding: '7rem 8vw', background: C.ivory }}>
        <SectionHeader eyebrow="Questions fréquentes" title="Tout ce que vous souhaitez savoir" subtitle="Nos réponses aux questions les plus posées par nos patients." />

        <div style={{ maxWidth: '760px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '.75rem' }}>
          {faqs.map(({ q, a }, i) => {
            const open = openFaq === i;
            return (
              <div key={i}
                style={{
                  background: C.white, border: `1px solid ${open ? C.goldLt : C.ivoryMid}`,
                  borderRadius: '14px', overflow: 'hidden',
                  boxShadow: open ? '0 8px 32px rgba(184,154,106,.12)' : 'none',
                  transition: 'all .25s ease',
                  animation: `fadeUp .6s ${0.06 * i}s ease both`, opacity: 0,
                }}>
                <button
                  onClick={() => setOpenFaq(open ? null : i)}
                  style={{
                    width: '100%', display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                    padding: '1.4rem 1.6rem', background: 'none', border: 'none', cursor: 'pointer',
                    textAlign: 'left', gap: '1rem',
                  }}>
                  <span style={{ fontFamily: C.fd, fontWeight: 400, fontSize: '1.05rem', color: open ? C.gold : C.charcoal, lineHeight: 1.4, flex: 1, transition: 'color .2s' }}>
                    {q}
                  </span>
                  <span style={{ color: open ? C.gold : C.muted, flexShrink: 0, transition: 'color .2s', transform: open ? 'rotate(0)' : 'rotate(0)' }}>
                    {open ? <Ico.Minus /> : <Ico.Plus />}
                  </span>
                </button>
                {open && (
                  <div style={{ padding: '0 1.6rem 1.5rem', animation: 'fadeIn .3s ease' }}>
                    <div style={{ width: '32px', height: '1px', background: C.goldLt, marginBottom: '1rem' }} />
                    <p style={{ fontSize: '.9rem', fontWeight: 300, color: C.ink, lineHeight: 1.8, margin: 0 }}>{a}</p>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </section>

      {/* ▓▓ CTA BANNER ▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓▓ */}
      <section style={{
        margin: '0 8vw 7rem',
        background: `linear-gradient(135deg, ${C.charcoal} 0%, #3a3730 100%)`,
        borderRadius: '28px', padding: '5rem 6rem',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        gap: '3rem', flexWrap: 'wrap',
        boxShadow: '0 40px 100px rgba(37,36,34,.2)',
        animation: 'fadeUp .8s ease both',
      }}>
        <div style={{ flex: 1, minWidth: '280px' }}>
          <span style={{ display: 'block', fontSize: '.7rem', fontWeight: 500, letterSpacing: '.15em', textTransform: 'uppercase', color: C.gold, marginBottom: '1rem' }}>Votre premier pas</span>
          <h2 style={{ fontFamily: C.fd, fontWeight: 300, fontSize: 'clamp(1.8rem,2.8vw,2.5rem)', color: C.ivory, margin: '0 0 .8rem', lineHeight: 1.2 }}>
            Prenez rendez-vous<br /><em style={{ fontStyle: 'italic', color: C.goldLt }}>dès aujourd'hui</em>
          </h2>
          <p style={{ fontSize: '.9rem', fontWeight: 300, color: C.mutedLt, lineHeight: 1.75, margin: 0, maxWidth: '42ch' }}>
            Consultation de diagnostic offerte pour tout nouveau patient. Notre équipe vous accueille 6 jours sur 7.
          </p>
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '.8rem', alignItems: 'flex-start' }}>
          <button
            onMouseEnter={() => setHBtn('cta')} onMouseLeave={() => setHBtn(null)}
            onClick={() => navigate('/contact')}
            style={{
              display: 'inline-flex', alignItems: 'center', gap: '8px',
              fontFamily: C.fb, fontSize: '.88rem', fontWeight: 500, letterSpacing: '.03em',
              background: hBtn === 'cta' ? C.gold : C.ivory,
              color: hBtn === 'cta' ? C.ivory : C.charcoal,
              border: 'none', borderRadius: '100px', padding: '.95rem 2.4rem',
              cursor: 'pointer', whiteSpace: 'nowrap',
              transform: hBtn === 'cta' ? 'translateY(-2px)' : 'none',
              boxShadow: hBtn === 'cta' ? '0 8px 28px rgba(184,154,106,.4)' : 'none',
              transition: 'all .22s ease',
            }}>
            Réserver ma consultation <Ico.Arrow />
          </button>
          <p style={{ fontSize: '.78rem', color: C.muted, margin: 0, paddingLeft: '.5rem' }}>
            📞 +212 5 37 XX XX XX — Réponse sous 2h
          </p>
        </div>
      </section>

    </div>
  );
}
